      "new": 1.0,
      "reason": "Maximize spreader width to the domain limit (1.0m) to enhance lateral heat distribution away from the chip center."
    },
    {
      "path": "components.2.height",
      "action": "set",
      "old": 0.1,
      "new": 0.15,
      "reason": "Increase spreader height by 50% (within 1.5x limit) to provide a larger vertical conduction path and thermal mass."
    }
  ],
  "expected_effects": [
    "Reduction of chip peak temperature below 85.0°C",
    "Improved lateral heat spreading efficiency",
    "Lower thermal resistance between chip and boundary conditions"
  ],
  "risk_notes": [
    "Geometric changes may approach design domain boundaries; ensure no overlap with other components occurs (y0=0.32 + h=0.15 = 0.47 < 0.5 limit).",
    "Aggressive geometry changes might alter flow paths if this were a conjugate problem, though less critical in pure conduction.",
    "If this step fails to satisfy constraints, the next logical step would be increasing base_material conductivity."
  ]
}
